DriveEncryption.query:
SELECT '' AS error WHERE NOT EXISTS (
  SELECT 1 FROM registry
  WHERE path = 'HKEY_LOCAL_MACHINE\SYSTEM\CurrentControlSet\Control\BitLockerStatus\BootStatus'
    AND data = '1'
);

BootOptions.query:
SELECT 'UEFI secure boot is disabled' AS error WHERE NOT EXISTS (
  SELECT 1 FROM registry
  WHERE path = 'HKEY_LOCAL_MACHINE\SYSTEM\CurrentControlSet\Control\SecureBoot\State\UEFISecureBootEnabled'
    AND data = '1'
);
